int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int A,B; scanf("%d %d", &A, &B);
        if(A==0) printf("https://www.codechef.com/practice\n");
        else if(B==0) printf("https://www.codechef.com/contests\n");
        else printf("https://discuss.codechef.com\n");
    }
    return 0;
}

