code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        A = int(next(it))
        B = int(next(it))
        if A == 0:
            out_lines.append("https://www.codechef.com/practice")
        elif B == 0:
            out_lines.append("https://www.codechef.com/contests")
        else:
            out_lines.append("https://discuss.codechef.com")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

